/**
 * Liquid Glass Effect - Fixed & Optimized
 * Handles SVG filter injection and browser fallbacks
 */
(function($, window, document) {
    'use strict';

    const LiquidGlass = {
        config: {
            safari: /^((?!chrome|android).)*safari/i.test(navigator.userAgent),
            firefox: typeof InstallTrigger !== 'undefined',
            filters: [
                {id: 1, class: 'glass3'},
                {id: 2, class: 'glass4'},
                {id: 3, class: 'glass5'},
                {id: 4, class: 'glass6'}
            ]
        },

        init: function() {
            this.bindEvents();
            this.checkExistingElements();
            
            // Immediate execution for already loaded DOM
            if (document.readyState !== 'loading') {
                this.processAll();
            }
        },

        bindEvents: function() {
            // Elementor Frontend Hook
            $(window).on('elementor/frontend/init', () => {
                if (window.elementorFrontend?.hooks) {
                    window.elementorFrontend.hooks.addAction(
                        'frontend/element_ready/global', 
                        ($scope) => this.processScope($scope)
                    );
                }
            });

            // DOM Ready Fallback
            $(document).ready(() => this.processAll());
            
            // Window Load (for cached pages)
            $(window).on('load', () => this.processAll());
        },

        checkExistingElements: function() {
            // Quick check if we need to do anything
            if ($('[class*="xpro-glass-effect__glass"]').length) {
                this.ensureFiltersExist();
            }
        },

        processAll: function() {
            const $elements = $('[class*="xpro-glass-effect__glass"]');
            if ($elements.length) {
                this.processScope($elements);
            }
        },

        processScope: function($scope) {
            if (!$scope?.length) return;

            const self = this;
            
            $scope.each(function() {
                const $el = $(this);
                const classes = $el.attr('class') || '';
                
                // Browser fallback: Convert advanced effects to glass1
                if (self.config.safari || self.config.firefox) {
                    self.applyFallback($el, classes);
                    return;
                }

                // Ensure SVG filters exist for advanced effects
                self.config.filters.forEach(filter => {
                    if (classes.includes(filter.class) || 
                        $el.find(`[class*="${filter.class}"]`).length) {
                        self.ensureFilter(filter.id);
                    }
                });
            });
        },

        applyFallback: function($el, classes) {
            // Replace glass3-6 with glass1 for unsupported browsers
            const newClasses = classes.split(/\s+/).map(cls => {
                if (cls.startsWith('xpro-glass-effect__glass') && 
                    !['xpro-glass-effect__glass1', 'xpro-glass-effect__glass2'].includes(cls)) {
                    return 'xpro-glass-effect__glass1';
                }
                return cls;
            }).join(' ');
            
            if (newClasses !== classes) {
                $el.attr('class', newClasses);
            }
        },

        ensureFilter: function(id) {
            const filterId = `glass-distortion${id}`;
            if (document.getElementById(filterId)) return;

            // Create SVG if missing
            const svgData = [
                {freq: '0.004 0.004', scale: 125},
                {freq: '0.007 0.007', scale: 111},
                {freq: '0.02 0.02', scale: 81},
                {freq: '0.015 0.015', scale: 179}
            ][id - 1];

            if (!svgData) return;

            const svg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
            svg.setAttribute('class', `xpro-glass-svg-${id}`);
            svg.setAttribute('width', '0');
            svg.setAttribute('height', '0');
            svg.style.cssText = 'position:absolute;left:-9999px;overflow:hidden;visibility:hidden;';
            
            svg.innerHTML = `
                <defs>
                    <filter id="${filterId}" x="0%" y="0%" width="100%" height="100%">
                        <feTurbulence type="fractalNoise" baseFrequency="${svgData.freq}" numOctaves="2" seed="92" result="noise"/>
                        <feGaussianBlur in="noise" stdDeviation="2" result="blurred"/>
                        <feDisplacementMap in="SourceGraphic" in2="blurred" scale="${svgData.scale}" xChannelSelector="R" yChannelSelector="G"/>
                    </filter>
                </defs>
            `;
            
            document.body.appendChild(svg);
        },

        ensureFiltersExist: function() {
            // Pre-create all filters to avoid race conditions
            this.config.filters.forEach(filter => this.ensureFilter(filter.id));
        }
    };

    // Initialize
    LiquidGlass.init();

})(jQuery, window, document);
